  "/ru/opendata/category/21/"
];

const texts = $json.linkText;
const urls = $json.linkUrl;

const categories = [];

for (let i = 0; i < urls.length; i++) {

  if (!mainCategories.includes(urls[i])) {
    categories.push({
      linkText: texts[i],
      linkUrl: urls[i]
    });
  }

}

return [
  {
    json: {
      chatInput: $json.chatInput,
      categories: categories
    }
  }
];

let txt = $json.text;

// Удаляем ```json и ```
txt = txt.replace(/```json\s*/i, "");
txt = txt.replace(/```/g, "");
txt = txt.trim();

// Преобразуем в объект
const obj = JSON.parse(txt);

return [
{
json:{
selectedUrl:obj.selectedUrl,
selectedCategory:obj.selectedCategory,

chatInput:$input.first().json.chatInput
}
}
];

